CREATE TABLE users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255),email VARCHAR(255) UNIQUE,phone VARCHAR(80),password_hash VARCHAR(255),role VARCHAR(50) DEFAULT 'member',status VARCHAR(50) DEFAULT 'Active',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE password_resets(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,token VARCHAR(255) UNIQUE,expires_at DATETIME,used_at DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE site_settings(id INT AUTO_INCREMENT PRIMARY KEY,setting_key VARCHAR(100) UNIQUE,setting_value TEXT);
CREATE TABLE membership_types(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(80) UNIQUE,annual_fee DECIMAL(10,2),description TEXT,sort_order INT DEFAULT 0,active TINYINT DEFAULT 1);
CREATE TABLE membership_applications(id INT AUTO_INCREMENT PRIMARY KEY,reference VARCHAR(80) UNIQUE,full_name VARCHAR(255),email VARCHAR(255),phone VARCHAR(80),membership_type VARCHAR(80),business_name VARCHAR(255),industry VARCHAR(255),seven_mountain VARCHAR(255),province VARCHAR(255),directory_consent TINYINT DEFAULT 0,payment_reference VARCHAR(255),status VARCHAR(80),admin_notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE memberships(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,membership_number VARCHAR(80) UNIQUE,membership_type VARCHAR(80),status VARCHAR(80),start_date DATE,expiry_date DATE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE businesses(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,name VARCHAR(255),category VARCHAR(255),seven_mountain VARCHAR(255),description TEXT,whatsapp VARCHAR(80),email VARCHAR(255),website VARCHAR(255),logo_url VARCHAR(255),status VARCHAR(80) DEFAULT 'Draft',featured TINYINT DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE village_space_types(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) UNIQUE,price_member DECIMAL(10,2),price_non_member DECIMAL(10,2),sort_order INT DEFAULT 0,active TINYINT DEFAULT 1);
CREATE TABLE village_layout_items(id INT AUTO_INCREMENT PRIMARY KEY,item_type VARCHAR(80),label VARCHAR(255),x_pos INT,y_pos INT,width INT,height INT,color VARCHAR(50),notes TEXT,zone VARCHAR(120),status VARCHAR(80),is_public TINYINT DEFAULT 1,z_index INT DEFAULT 1);
CREATE TABLE village_bookings(id INT AUTO_INCREMENT PRIMARY KEY,reference VARCHAR(80) UNIQUE,applicant_name VARCHAR(255),business_name VARCHAR(255),email VARCHAR(255),phone VARCHAR(80),is_member TINYINT,membership_number VARCHAR(80),space_type VARCHAR(255),amount_due DECIMAL(10,2),payment_reference VARCHAR(255),status VARCHAR(80),stand_number VARCHAR(80),admin_notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE sponsor_packages(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120),price DECIMAL(10,2),benefits TEXT,sort_order INT DEFAULT 0,active TINYINT DEFAULT 1);
CREATE TABLE sponsor_enquiries(id INT AUTO_INCREMENT PRIMARY KEY,reference VARCHAR(80) UNIQUE,organisation VARCHAR(255),contact_person VARCHAR(255),email VARCHAR(255),phone VARCHAR(80),sponsorship_level VARCHAR(120),notes TEXT,status VARCHAR(80),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE events(id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(255),event_type VARCHAR(120),event_date DATE,description TEXT,active TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE opportunities(id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(255),opportunity_type VARCHAR(120),description TEXT,active TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE contact_messages(id INT AUTO_INCREMENT PRIMARY KEY,reference VARCHAR(80) UNIQUE,name VARCHAR(255),email VARCHAR(255),phone VARCHAR(80),message TEXT,status VARCHAR(80),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
